import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import "./StackCarousel.css";

function StackCarousel({
  cards = [],
  autoPlay = true,
  interval = 3000,
}) {
  const [stack, setStack] = useState(cards);
  const [isHovered, setIsHovered] = useState(false);

  useEffect(() => {
    if (!autoPlay || isHovered) return;

    const timer = setInterval(() => {
      rotateStack();
    }, interval);

    return () => clearInterval(timer);
  }, [stack, autoPlay, isHovered]);

  const rotateStack = () => {
    setStack((prev) => {
      const updated = [...prev];
      const first = updated.shift();
      updated.push(first);
      return updated;
    });
  };

  return (
    <div
      className="stack-container"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {stack.map((card, index) => (
        <motion.div
          key={card.id}
          className={`stack-card ${card.variant || ""}`}
          drag={index === 0 ? "x" : false}
          dragConstraints={{ left: 0, right: 0 }}
          onDragEnd={(e, info) => {
            if (info.offset.x < -80) rotateStack();
          }}
          whileHover={
            index === 0
              ? { scale: 1.02, y: -4 }
              : {}
          }
          animate={{
            y: index * 14,
            scale: 1 - index * 0.05,
            opacity: index > 4 ? 0 : 1,
          }}
          transition={{
            type: "spring",
            stiffness: 220,
            damping: 22,
          }}
          style={{
            zIndex: stack.length - index,
          }}
        >
          {card.content}
        </motion.div>
      ))}
    </div>
  );
}

export default StackCarousel;

.stack-container {
  position: relative;
  width: 380px;
  height: 240px;
}

/* Base Card */

.stack-card {
  position: absolute;
  width: 100%;
  height: 200px;
  border-radius: 18px;
  padding: 20px;
  backdrop-filter: blur(14px);
  background: rgba(15, 20, 25, 0.8);
  box-shadow:
    0 20px 50px rgba(0, 0, 0, 0.6),
    inset 0 0 0 1px rgba(255, 255, 255, 0.06);
  color: #e4e7eb;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  overflow: hidden;
  cursor: grab;
}

.stack-card:active {
  cursor: grabbing;
}

/* Glass edge highlight */

.stack-card::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 18px;
  background: linear-gradient(
    120deg,
    rgba(255, 255, 255, 0.12),
    transparent 40%
  );
  opacity: 0.15;
  pointer-events: none;
}

/* Original Rich Color Variants */

.stack-card.blue {
  background: linear-gradient(
    135deg,
    rgba(40, 80, 180, 0.6),
    rgba(10, 20, 40, 0.9)
  );
}

.stack-card.green {
  background: linear-gradient(
    135deg,
    rgba(40, 180, 120, 0.6),
    rgba(10, 25, 20, 0.9)
  );
}

.stack-card.orange {
  background: linear-gradient(
    135deg,
    rgba(255, 140, 80, 0.6),
    rgba(30, 15, 10, 0.9)
  );
}
